{"code": "import json
import re

# Access results from storage directly
clinical_file = locals()['var_functions.query_db:22']
if isinstance(clinical_file, str) and clinical_file.endswith('.json'):
    with open(clinical_file, 'r') as f:
        clinical_records = json.load(f)
else:
    clinical_records = locals()['var_functions.query_db:22']

# Get CDH1 mutation data
cdh1_mutations = locals()['var_functions.query_db:18']

# Extract BRCA female patient data
female_brca_patients = []
for record in clinical_records:
    description = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')

    match = re.search(r'(TCGA-\w{2}-\w{4})', description)
    if match:
        barcode = match.group(1)
        female_brca_patients.append({
            'ParticipantBarcode': barcode,
            'histological_type': hist_type
        })

# Create set of CDH1 mutation patients
cdh1_positive = set()
for mut in cdh1_mutations:
    cdh1_positive.add(mut['ParticipantBarcode'])

# Build contingency table
contingency_data = []
for patient in female_brca_patients:
    barcode = patient['ParticipantBarcode']
    hist_type = patient['histological_type']

    if not hist_type or 'Other' in hist_type or hist_type.lower() == 'unknown':
        continue

    has_cdh1 = barcode in cdh1_positive

    contingency_data.append({
        'ParticipantBarcode': barcode,
        'histological_type': hist_type,
        'cdh1_mutation': has_cdh1
    })

# Count by histology and CDH1 status
histology_counts = {}
for item in contingency_data:
    hist = item['histological_type']
    cdh1 = item['cdh1_mutation']

    if hist not in histology_counts:
        histology_counts[hist] = {'cdh1_positive': 0, 'cdh1_negative': 0}

    if cdh1:
        histology_counts[hist]['cdh1_positive'] += 1
    else:
        histology_counts[hist]['cdh1_negative'] += 1

print('__RESULT__:')
print(json.dumps({
    'total_female_brca': len(female_brca_patients),
    'with_known_histology': len(contingency_data),
    'cdh1_positive_total': sum(1 for x in contingency_data if x['cdh1_mutation']),
    'histology_counts': histology_counts
}))"}

